        [1, 2, 0, 3, 4],              # Island: water, sand, grass, forest, mountain
        [8, 1, 2, 0],                  # Coastline: deep water, water, sand, grass
        [0, 9, 7, 6, 3],              # Village: grass, path, house, town, forest
