    def _enter_wfc_mode(self):
        """Enter WFC mode — show preset menu."""
        self.wfc_menu = True
        self.wfc_menu_sel = 0
        self._flash("Wave Function Collapse — select a configuration")

    def _exit_wfc_mode(self):
        """Exit WFC mode."""
        self.wfc_mode = False
        self.wfc_menu = False
        self.wfc_running = False
        self.wfc_grid = []
        self.wfc_collapsed = []
        self._flash("WFC mode OFF")

    def _wfc_init(self, preset_idx: int):
        """Initialize WFC simulation with the given preset."""
        import random as _rng
        name, _desc, num_tiles, _tile_names, adj_rules = self.WFC_PRESETS[preset_idx]

        self.wfc_preset_name = name
        self.wfc_num_tiles = num_tiles
        self.wfc_preset_idx = preset_idx

        # Make adjacency bidirectional/symmetric
        opposites = {"N": "S", "S": "N", "E": "W", "W": "E"}
        self.wfc_adjacency = {}
        for t in range(num_tiles):
            self.wfc_adjacency[t] = {}
            for d in ("N", "S", "E", "W"):
                self.wfc_adjacency[t][d] = set(adj_rules.get(t, {}).get(d, set()))

        # Enforce symmetry: if tile A allows tile B to its North,
        # then tile B must allow tile A to its South
        for t in range(num_tiles):
            for d in ("N", "S", "E", "W"):
                od = opposites[d]
                for neighbor in list(self.wfc_adjacency[t][d]):
                    self.wfc_adjacency[neighbor][od].add(t)

        max_y, max_x = self.stdscr.getmaxyx()
        self.wfc_rows = max(5, max_y - 3)
        self.wfc_cols = max(5, (max_x - 1) // 2)

        rows, cols = self.wfc_rows, self.wfc_cols
        all_tiles = set(range(num_tiles))

        # Initialize every cell with all possibilities
        self.wfc_grid = [[set(all_tiles) for _ in range(cols)] for _ in range(rows)]
        self.wfc_collapsed = [[-1] * cols for _ in range(rows)]

        self.wfc_generation = 0
        self.wfc_contradiction = False
        self.wfc_complete = False
        self.wfc_running = False

        self.wfc_menu = False
        self.wfc_mode = True
        self._flash(f"WFC: {name} — Space to auto-run, n to step")

    def _wfc_step(self):
        """Perform one WFC collapse step: pick lowest-entropy cell, collapse, propagate."""
        import random as _rng

        if self.wfc_complete or self.wfc_contradiction:
            return

        rows, cols = self.wfc_rows, self.wfc_cols
        grid = self.wfc_grid
        collapsed = self.wfc_collapsed

        # Find the uncollapsed cell with lowest entropy (smallest number of possibilities)
        min_entropy = self.wfc_num_tiles + 1
        candidates = []
        for r in range(rows):
            for c in range(cols):
                if collapsed[r][c] == -1:
                    e = len(grid[r][c])
                    if e == 0:
                        # Contradiction — no valid tiles for this cell
                        self.wfc_contradiction = True
                        self._flash("Contradiction! No valid tile. Press r to restart.")
                        return
                    if e < min_entropy:
                        min_entropy = e
                        candidates = [(r, c)]
                    elif e == min_entropy:
                        candidates.append((r, c))

        if not candidates:
            # All cells collapsed
            self.wfc_complete = True
            self.wfc_running = False
            self._flash("WFC complete! All cells collapsed.")
            return

        # Pick a random cell among lowest-entropy candidates
        cr, cc = _rng.choice(candidates)

        # Collapse: pick a random tile from possibilities
        tile = _rng.choice(list(grid[cr][cc]))
        grid[cr][cc] = {tile}
        collapsed[cr][cc] = tile

        # Propagate constraints
        self._wfc_propagate(cr, cc)

        self.wfc_generation += 1

    def _wfc_propagate(self, start_r: int, start_c: int):
        """Propagate constraints from a collapsed cell using BFS."""
        rows, cols = self.wfc_rows, self.wfc_cols
        grid = self.wfc_grid
        collapsed = self.wfc_collapsed
        adjacency = self.wfc_adjacency

        # Direction offsets: (dr, dc, direction_name)
        dirs = [(-1, 0, "N"), (1, 0, "S"), (0, 1, "E"), (0, -1, "W")]
        opposites = {"N": "S", "S": "N", "E": "W", "W": "E"}

        stack = [(start_r, start_c)]

        while stack:
            r, c = stack.pop()
            current_tiles = grid[r][c]

            for dr, dc, d in dirs:
                nr, nc = r + dr, c + dc
                if nr < 0 or nr >= rows or nc < 0 or nc >= cols:
                    continue
                if collapsed[nr][nc] != -1:
                    continue  # already collapsed, skip

                # Compute what tiles are allowed in neighbor based on current cell
                allowed = set()
                for t in current_tiles:
                    allowed |= adjacency[t][d]

                # Intersect with neighbor's current possibilities
                neighbor_before = len(grid[nr][nc])
                grid[nr][nc] &= allowed

                if len(grid[nr][nc]) == 0:
                    self.wfc_contradiction = True
                    return

                # If we reduced possibilities, propagate further
                if len(grid[nr][nc]) < neighbor_before:
                    # Auto-collapse if only one option left
                    if len(grid[nr][nc]) == 1:
                        collapsed[nr][nc] = next(iter(grid[nr][nc]))
                    stack.append((nr, nc))

    def _handle_wfc_menu_key(self, key: int) -> bool:
        """Handle input in WFC preset menu."""
        n = len(self.WFC_PRESETS)
        if key in (ord("j"), curses.KEY_DOWN):
            self.wfc_menu_sel = (self.wfc_menu_sel + 1) % n
        elif key in (ord("k"), curses.KEY_UP):
            self.wfc_menu_sel = (self.wfc_menu_sel - 1) % n
        elif key in (ord("\n"), ord("\r")):
            self._wfc_init(self.wfc_menu_sel)
        elif key in (ord("q"), 27):
            self.wfc_menu = False
            self._flash("WFC cancelled")
        return True

    def _handle_wfc_key(self, key: int) -> bool:
        """Handle input in active WFC simulation."""
        if key == ord(" "):
            if self.wfc_complete or self.wfc_contradiction:
                return True
            self.wfc_running = not self.wfc_running
            self._flash("Running" if self.wfc_running else "Paused")
        elif key in (ord("n"), ord(".")):
            self._wfc_step()
        elif key == ord("r"):
            # Restart with same preset
            self._wfc_init(self.wfc_preset_idx)
        elif key == ord("s") or key == ord("S"):
            # Adjust steps per frame
            if key == ord("s"):
                self.wfc_steps_per_frame = min(50, self.wfc_steps_per_frame + 1)
            else:
                self.wfc_steps_per_frame = max(1, self.wfc_steps_per_frame - 1)
            self._flash(f"Steps/frame: {self.wfc_steps_per_frame}")
        elif key in (ord("q"), 27):
            self._exit_wfc_mode()
        else:
            return True
        return True

    def _draw_wfc_menu(self, max_y: int, max_x: int):
        """Draw the WFC preset selection menu."""
        self.stdscr.erase()
        title = "── Wave Function Collapse ── Select Configuration ──"
        try:
            self.stdscr.addstr(1, max(0, (max_x - len(title)) // 2), title,
                               curses.color_pair(7) | curses.A_BOLD)
        except curses.error:
            pass

        for i, (name, desc, num_tiles, tile_names, _adj) in enumerate(self.WFC_PRESETS):
            y = 3 + i * 2
            if y >= max_y - 2:
                break
            tiles_str = ", ".join(tile_names[:4])
            if len(tile_names) > 4:
                tiles_str += ", ..."
            line = f"  {name:<14s}  {desc}  [{tiles_str}]"
            attr = curses.color_pair(6)
            if i == self.wfc_menu_sel:
                attr = curses.color_pair(7) | curses.A_REVERSE
            try:
                self.stdscr.addstr(y, 2, line[:max_x - 4], attr)
            except curses.error:
                pass

        hint = " [j/k]=navigate  [Enter]=select  [q]=cancel"
        try:
            self.stdscr.addstr(max_y - 1, 0, hint[:max_x - 1],
                               curses.color_pair(6) | curses.A_DIM)
        except curses.error:
            pass

    def _draw_wfc(self, max_y: int, max_x: int):
        """Draw the active WFC simulation."""
        self.stdscr.erase()
        rows, cols = self.wfc_rows, self.wfc_cols
        collapsed = self.wfc_collapsed
        grid = self.wfc_grid
        preset_tiles = self.WFC_PRESET_TILES[self.wfc_preset_idx]

        # Count collapsed cells
        num_collapsed = sum(1 for r in range(rows) for c in range(cols) if collapsed[r][c] != -1)
        total = rows * cols
        pct = num_collapsed * 100 // total if total > 0 else 0

        # Title bar
        if self.wfc_contradiction:
            state = "✗ CONTRADICTION"
        elif self.wfc_complete:
            state = "✓ COMPLETE"
        elif self.wfc_running:
            state = "▶ RUNNING"
        else:
            state = "⏸ PAUSED"

        title = (f" WFC: {self.wfc_preset_name}  |  step {self.wfc_generation}"
                 f"  |  {pct}% collapsed  |  {state}")
        try:
            self.stdscr.addstr(0, 0, title[:max_x - 1],
                               curses.color_pair(7) | curses.A_BOLD)
        except curses.error:
            pass

        view_rows = min(rows, max_y - 3)
        view_cols = min(cols, (max_x - 1) // 2)

        for r in range(view_rows):
            for c in range(view_cols):
                tile_idx = collapsed[r][c]
                if tile_idx != -1:
                    # Collapsed cell — render the tile
                    display_idx = preset_tiles[tile_idx] if tile_idx < len(preset_tiles) else 0
                    if display_idx < len(self.WFC_TILE_CHARS):
                        ch, color = self.WFC_TILE_CHARS[display_idx]
                    else:
                        ch, color = "??", 1
                    attr = curses.color_pair(color)
                    try:
                        self.stdscr.addstr(1 + r, c * 2, ch, attr)
                    except curses.error:
                        pass
                else:
                    # Uncollapsed — show entropy as brightness
                    entropy = len(grid[r][c])
                    if entropy <= 1:
                        ch = "!!"
                        attr = curses.color_pair(1) | curses.A_BOLD
                    elif entropy <= 2:
                        ch = "░░"
                        attr = curses.color_pair(5) | curses.A_BOLD
                    elif entropy <= 3:
                        ch = "▒▒"
                        attr = curses.color_pair(5)
                    else:
                        ch = "▓▓"
                        attr = curses.color_pair(5) | curses.A_DIM
                    try:
                        self.stdscr.addstr(1 + r, c * 2, ch, attr)
                    except curses.error:
                        pass

        # Bottom hint bar
        hint = " [Space]=run  [n]=step  [r]=restart  [s/S]=speed  [q]=quit"
        try:
            self.stdscr.addstr(max_y - 1, 0, hint[:max_x - 1],
                               curses.color_pair(6) | curses.A_DIM)
        except curses.error:
            pass


    # ══════════════════════════════════════════════════════════════════════
    #  Lightning / Dielectric Breakdown — Mode ^
    # ══════════════════════════════════════════════════════════════════════

    # Each preset: (name, description, eta, source)
    # eta = field exponent controlling branching (lower = more branching)
    # source = where discharge originates: "top", "center", "point"
    LIGHTNING_PRESETS = [
        ("Classic Lightning",
         "Top-to-bottom bolt — natural branching",
         2.0, "top"),
        ("Sparse Bolt",
         "High eta — fewer branches, straighter path",
         4.0, "top"),
        ("Dense Branching",
         "Low eta — heavily branched discharge",
         1.0, "top"),
        ("Lichtenberg Figure",
         "Center-outward — radial fractal pattern",
         1.5, "center"),
        ("Point Discharge",
         "Single point source — star-like pattern",
         2.0, "point"),
        ("Feathery Discharge",
         "Very low eta — maximum branching",
         0.5, "center"),
        ("Minimal Tree",
         "Moderate branching from top edge",
         3.0, "top"),
        ("Ball Lightning",
         "Center discharge — sparse and radial",
         3.5, "center"),
    ]

    def _enter_lightning_mode(self):
        """Enter Lightning / Dielectric Breakdown mode — show preset menu."""
        self.lightning_menu = True
        self.lightning_menu_sel = 0
        self._flash("Lightning / Dielectric Breakdown — select a scenario")

    def _exit_lightning_mode(self):
        """Exit Lightning mode."""
        self.lightning_mode = False
        self.lightning_menu = False
        self.lightning_running = False
        self.lightning_grid = []
        self.lightning_potential = []
        self.lightning_age = []
        self._flash("Lightning mode OFF")

    def _lightning_init(self, preset_idx: int):
        """Initialize lightning simulation with the given preset."""
        (name, _desc, eta, source) = self.LIGHTNING_PRESETS[preset_idx]
        self.lightning_preset_name = name
        self.lightning_generation = 0
        self.lightning_running = False
        self.lightning_eta = eta
        self.lightning_source = source

        max_y, max_x = self.stdscr.getmaxyx()
        self.lightning_rows = max(10, max_y - 4)
        self.lightning_cols = max(10, (max_x - 1) // 2)
        rows, cols = self.lightning_rows, self.lightning_cols

        # Initialize empty grid
        self.lightning_grid = [[0] * cols for _ in range(rows)]
        self.lightning_age = [[0] * cols for _ in range(rows)]
        self.lightning_channel_count = 0

        # Set initial discharge source
        if source == "top":
            # Discharge starts from center of top row
            c = cols // 2
            self.lightning_grid[0][c] = 1
            self.lightning_age[0][c] = 0
            self.lightning_channel_count = 1
        elif source == "center":
            # Discharge starts from center
            r, c = rows // 2, cols // 2
            self.lightning_grid[r][c] = 1
            self.lightning_age[r][c] = 0
            self.lightning_channel_count = 1
        elif source == "point":
            # Discharge from a single point near top-center
            r, c = rows // 4, cols // 2
            self.lightning_grid[r][c] = 1
            self.lightning_age[r][c] = 0
            self.lightning_channel_count = 1

        # Compute initial potential field
        self.lightning_potential = [[0.0] * cols for _ in range(rows)]
        self._lightning_solve_potential()

        self.lightning_menu = False
        self.lightning_mode = True
        self._flash(f"Lightning: {name} — Space to start")

    def _lightning_solve_potential(self):
        """Solve the electric potential using iterative relaxation (Laplace).

        Boundary conditions:
        - Discharge channel cells: potential = 0
        - Bottom row (or boundary for center/point): potential = 1
        - Other boundaries: Neumann (zero gradient)
        """
        grid = self.lightning_grid
        rows, cols = self.lightning_rows, self.lightning_cols
        pot = self.lightning_potential
        source = self.lightning_source

        # Initialize potential: channel=0, ground=1
        for r in range(rows):
            for c in range(cols):
                if grid[r][c] == 1:
                    pot[r][c] = 0.0
                else:
                    pot[r][c] = 0.5  # initial guess

        # Set ground boundary
        if source == "top":
            for c in range(cols):
                if grid[rows - 1][c] == 0:
                    pot[rows - 1][c] = 1.0
        else:
            # For center/point: ground is at all edges
            for c in range(cols):
                if grid[0][c] == 0:
                    pot[0][c] = 1.0
                if grid[rows - 1][c] == 0:
                    pot[rows - 1][c] = 1.0
            for r in range(rows):
                if grid[r][0] == 0:
                    pot[r][0] = 1.0
                if grid[r][cols - 1] == 0:
                    pot[r][cols - 1] = 1.0

        # Iterative Gauss-Seidel relaxation
        # Fewer iterations for speed; enough for reasonable field approximation
        iterations = min(80, max(rows, cols))
        for _ in range(iterations):
            for r in range(rows):
                for c in range(cols):
                    if grid[r][c] == 1:
                        continue  # channel is fixed at 0
                    # Ground boundary
                    if source == "top" and r == rows - 1:
                        continue
                    if source != "top":
                        if r == 0 or r == rows - 1 or c == 0 or c == cols - 1:
                            continue

                    # Average of neighbors (with boundary handling)
                    total = 0.0
                    count = 0
                    if r > 0:
                        total += pot[r - 1][c]
                        count += 1
                    if r < rows - 1:
                        total += pot[r + 1][c]
                        count += 1
                    if c > 0:
                        total += pot[r][c - 1]
                        count += 1
                    if c < cols - 1:
                        total += pot[r][c + 1]
                        count += 1
                    if count > 0:
                        pot[r][c] = total / count

    def _lightning_step(self):
        """Advance lightning simulation by one step.

        Dielectric Breakdown Model:
        1. Find all empty cells adjacent to the discharge channel (growth candidates)
        2. Compute growth probability proportional to (local E-field)^eta
        3. Pick one candidate weighted by probability and add it to channel
        4. Re-solve potential field
        """
        grid = self.lightning_grid
        pot = self.lightning_potential
        rows, cols = self.lightning_rows, self.lightning_cols
        eta = self.lightning_eta

        # Find growth candidates: empty cells adjacent to channel
        candidates = []
        for r in range(rows):
            for c in range(cols):
                if grid[r][c] == 1:
                    # Check 4-connected neighbors for empty cells
                    for dr, dc in ((-1, 0), (1, 0), (0, -1), (0, 1)):
                        nr, nc = r + dr, c + dc
                        if 0 <= nr < rows and 0 <= nc < cols:
                            if grid[nr][nc] == 0:
                                candidates.append((nr, nc))

        if not candidates:
            self.lightning_running = False
            return

        # Remove duplicates
        candidates = list(set(candidates))

        # Compute weights: potential^eta (potential at candidate gives E-field proxy)
        weights = []
        for (r, c) in candidates:
            phi = pot[r][c]
            w = phi ** eta if phi > 0 else 0.0
            weights.append(w)

        total_w = sum(weights)
        if total_w <= 0:
            # No valid growth sites
            self.lightning_running = False
            return

        # Weighted random selection
        rval = random.random() * total_w
        cumulative = 0.0
        chosen = candidates[0]
        for i, (r, c) in enumerate(candidates):
            cumulative += weights[i]
            if cumulative >= rval:
                chosen = (r, c)
                break

        # Add chosen cell to discharge channel
        cr, cc = chosen
        grid[cr][cc] = 1
        self.lightning_age[cr][cc] = self.lightning_generation
        self.lightning_channel_count += 1

        # Check if we've reached ground
        source = self.lightning_source
        reached_ground = False
        if source == "top" and cr == rows - 1:
            reached_ground = True
        elif source != "top":
            if cr == 0 or cr == rows - 1 or cc == 0 or cc == cols - 1:
                reached_ground = True

        if reached_ground:
            self.lightning_running = False

        # Re-solve potential
        self._lightning_solve_potential()
        self.lightning_generation += 1

    def _handle_lightning_menu_key(self, key: int) -> bool:
        """Handle input in lightning preset menu."""
        n = len(self.LIGHTNING_PRESETS)
        if key in (ord("j"), curses.KEY_DOWN):
            self.lightning_menu_sel = (self.lightning_menu_sel + 1) % n
        elif key in (ord("k"), curses.KEY_UP):
            self.lightning_menu_sel = (self.lightning_menu_sel - 1) % n
        elif key in (ord("\n"), ord("\r")):
            self._lightning_init(self.lightning_menu_sel)
        elif key in (ord("q"), 27):
            self.lightning_menu = False
            self._flash("Lightning cancelled")
        return True

    def _handle_lightning_key(self, key: int) -> bool:
        """Handle input in active lightning simulation."""
        if key == ord(" "):
            self.lightning_running = not self.lightning_running
        elif key in (ord("n"), ord(".")):
            for _ in range(self.lightning_steps_per_frame):
                self._lightning_step()
        elif key == ord("r"):
            idx = next((i for i, p in enumerate(self.LIGHTNING_PRESETS)
                        if p[0] == self.lightning_preset_name), 0)
            self._lightning_init(idx)
            self.lightning_running = False
        elif key in (ord("R"), ord("m")):
            self.lightning_mode = False
            self.lightning_running = False
            self.lightning_menu = True
            self.lightning_menu_sel = 0
        elif key == ord("e") or key == ord("E"):
            delta = 0.25 if key == ord("e") else -0.25
            self.lightning_eta = max(0.1, min(10.0, self.lightning_eta + delta))
            self._flash(f"Eta (branching) = {self.lightning_eta:.2f}")
        elif key == ord("+") or key == ord("="):
            self.lightning_steps_per_frame = min(20, self.lightning_steps_per_frame + 1)
            self._flash(f"Steps/frame: {self.lightning_steps_per_frame}")
        elif key == ord("-"):
            self.lightning_steps_per_frame = max(1, self.lightning_steps_per_frame - 1)
            self._flash(f"Steps/frame: {self.lightning_steps_per_frame}")
        elif key == ord("<") or key == ord(","):
            self.speed_idx = max(0, self.speed_idx - 1)
        elif key == ord(">"):
            self.speed_idx = min(len(SPEEDS) - 1, self.speed_idx + 1)
        elif key in (ord("q"), 27):
            self._exit_lightning_mode()
        else:
            return True
        return True

