    def _erosion_generate_terrain(self, rows: int, cols: int, terrain_type: str) -> list:
        """Generate a heightmap using layered noise (diamond-square inspired)."""
        terrain = [[0.0] * cols for _ in range(rows)]

        # Use multiple octaves of random smooth noise
        def _smooth_noise(freq: float, amp: float):
            # Generate sparse random grid then interpolate
            sr = max(2, int(rows / freq))
            sc = max(2, int(cols / freq))
            sparse_r = max(2, rows // sr + 2)
            sparse_c = max(2, cols // sc + 2)
            sparse = [[random.random() for _ in range(sparse_c)] for _ in range(sparse_r)]
            for r in range(rows):
                for c in range(cols):
                    gr = r / sr
                    gc = c / sc
                    r0 = int(gr) % sparse_r
                    r1 = (r0 + 1) % sparse_r
                    c0 = int(gc) % sparse_c
                    c1 = (c0 + 1) % sparse_c
                    fr = gr - int(gr)
                    fc = gc - int(gc)
                    # Bilinear interpolation
                    top = sparse[r0][c0] * (1 - fc) + sparse[r0][c1] * fc
                    bot = sparse[r1][c0] * (1 - fc) + sparse[r1][c1] * fc
                    val = top * (1 - fr) + bot * fr
                    terrain[r][c] += val * amp

        if terrain_type == "gentle":
            _smooth_noise(4, 0.5)
            _smooth_noise(8, 0.3)
            _smooth_noise(16, 0.15)
        elif terrain_type == "steep":
            _smooth_noise(3, 0.6)
            _smooth_noise(6, 0.3)
            _smooth_noise(12, 0.1)
            # Add ridge line
            mid_c = cols // 2
            for r in range(rows):
                for c in range(cols):
                    dist = abs(c - mid_c) / max(1, cols)
                    terrain[r][c] += 0.3 * max(0, 1.0 - dist * 3)
        elif terrain_type == "plateau":
            _smooth_noise(5, 0.3)
            _smooth_noise(10, 0.15)
            # Flat top with cliff edges
            for r in range(rows):
                for c in range(cols):
                    edge_dist = min(r, rows - 1 - r, c, cols - 1 - c) / max(1, min(rows, cols) * 0.3)
                    terrain[r][c] += 0.4 * min(1.0, edge_dist)
        elif terrain_type == "rough":
            _smooth_noise(3, 0.35)
            _smooth_noise(6, 0.25)
            _smooth_noise(12, 0.2)
            _smooth_noise(24, 0.15)
        elif terrain_type == "alpine":
            _smooth_noise(3, 0.5)
            _smooth_noise(6, 0.3)
            _smooth_noise(12, 0.15)
            # Exaggerate peaks
            for r in range(rows):
                for c in range(cols):
                    terrain[r][c] = terrain[r][c] ** 1.3
        elif terrain_type == "hills":
            _smooth_noise(5, 0.4)
            _smooth_noise(10, 0.3)
            _smooth_noise(20, 0.1)
        elif terrain_type == "mesa":
            _smooth_noise(4, 0.3)
            _smooth_noise(8, 0.2)
            # Quantize heights for layered look
            for r in range(rows):
                for c in range(cols):
                    terrain[r][c] = int(terrain[r][c] * 6) / 6.0
        elif terrain_type == "volcano":
            _smooth_noise(6, 0.2)
            _smooth_noise(12, 0.1)
            # Central peak
            cr_center, cc_center = rows // 2, cols // 2
            max_dist = math.sqrt(cr_center ** 2 + cc_center ** 2)
            for r in range(rows):
                for c in range(cols):
                    dist = math.sqrt((r - cr_center) ** 2 + (c - cc_center) ** 2)
                    terrain[r][c] += 0.6 * max(0, 1.0 - dist / (max_dist * 0.6))

        # Normalize to [0, 1]
        min_h = min(terrain[r][c] for r in range(rows) for c in range(cols))
        max_h = max(terrain[r][c] for r in range(rows) for c in range(cols))
        rng = max_h - min_h if max_h > min_h else 1.0
        for r in range(rows):
            for c in range(cols):
                terrain[r][c] = (terrain[r][c] - min_h) / rng
        return terrain

    def _erosion_init(self, preset_idx: int):
        """Initialize hydraulic erosion simulation with the given preset."""
        (name, _desc, rain, evap, sol, dep, ttype) = self.EROSION_PRESETS[preset_idx]
        self.erosion_preset_name = name
        self.erosion_generation = 0
        self.erosion_running = False
        self.erosion_rain_rate = rain
        self.erosion_evap_rate = evap
        self.erosion_solubility = sol
        self.erosion_deposition = dep
        self.erosion_total_eroded = 0.0

        max_y, max_x = self.stdscr.getmaxyx()
        self.erosion_rows = max(10, max_y - 4)
        self.erosion_cols = max(10, (max_x - 1) // 2)
        rows, cols = self.erosion_rows, self.erosion_cols

        self.erosion_terrain = self._erosion_generate_terrain(rows, cols, ttype)
        self.erosion_water = [[0.0] * cols for _ in range(rows)]
        self.erosion_sediment = [[0.0] * cols for _ in range(rows)]

        self.erosion_menu = False
        self.erosion_mode = True
        self._flash(f"Erosion: {name} — Space to start")

    def _erosion_step(self):
        """Advance hydraulic erosion by one step.

        Simplified shallow-water erosion model:
        1. Rain — add water uniformly (with slight randomness)
        2. Flow — water flows to lowest neighbor(s), carrying sediment
        3. Erode — flowing water picks up sediment proportional to flow speed
        4. Deposit — sediment drops when water slows or pools
        5. Evaporate — water evaporates, depositing remaining sediment
        """
        terrain = self.erosion_terrain
        water = self.erosion_water
        sediment = self.erosion_sediment
        rows, cols = self.erosion_rows, self.erosion_cols
        rain = self.erosion_rain_rate
        evap = self.erosion_evap_rate
        sol = self.erosion_solubility
        dep = self.erosion_deposition

        # 1. Rainfall — add water everywhere with some spatial variation
        for r in range(rows):
            for c in range(cols):
                water[r][c] += rain * (0.8 + 0.4 * random.random())

        # 2–4. Flow, erosion, deposition
        new_water = [[0.0] * cols for _ in range(rows)]
        new_sediment = [[0.0] * cols for _ in range(rows)]
        total_eroded = 0.0

        for r in range(rows):
            for c in range(cols):
                h = terrain[r][c] + water[r][c]  # effective height (terrain + water)
                w = water[r][c]
                s = sediment[r][c]

                if w < 1e-6:
                    new_water[r][c] += w
                    new_sediment[r][c] += s
                    continue

                # Find neighbors and height differences
                neighbors = []
                for dr, dc in ((-1, 0), (1, 0), (0, -1), (0, 1)):
                    nr, nc = r + dr, c + dc
                    if 0 <= nr < rows and 0 <= nc < cols:
                        nh = terrain[nr][nc] + water[nr][nc]
                        if nh < h:
                            neighbors.append((nr, nc, h - nh))

                if not neighbors:
                    # No downhill — water pools here
                    new_water[r][c] += w
                    # Deposit sediment when pooling
                    deposit_amt = min(s, dep * w)
                    terrain[r][c] += deposit_amt
                    new_sediment[r][c] += s - deposit_amt
                    continue

                # Distribute water to lower neighbors proportional to height diff
                total_diff = sum(d for _, _, d in neighbors)
                flow_out = min(w, total_diff * 0.5)  # limit flow to available water

                for nr, nc, diff in neighbors:
                    frac = diff / total_diff
                    flow = flow_out * frac
                    # Erosion: proportional to flow velocity (slope * flow)
                    velocity = diff * flow
                    erode_amt = sol * velocity
                    erode_amt = min(erode_amt, terrain[r][c] * 0.1)  # cap erosion
                    terrain[r][c] -= erode_amt
                    total_eroded += erode_amt

                    # Move water and sediment (existing + newly eroded) to neighbor
                    sed_flow = (s * frac * flow_out / max(w, 1e-9)) + erode_amt
                    new_water[nr][nc] += flow
                    new_sediment[nr][nc] += sed_flow

                # Keep remaining water and sediment at current cell
                remaining_w = w - flow_out
                remaining_s = s * (1.0 - flow_out / max(w, 1e-9))
                remaining_s = max(0.0, remaining_s)
                new_water[r][c] += remaining_w
                new_sediment[r][c] += remaining_s

        # 5. Evaporation and final deposition
        for r in range(rows):
            for c in range(cols):
                w = new_water[r][c]
                s = new_sediment[r][c]
                # Evaporate
                evap_amt = min(w, evap)
                w -= evap_amt
                # Deposit sediment from evaporating water
                if w < 1e-6 and s > 0:
                    terrain[r][c] += s
                    s = 0.0
                elif s > dep * 2:
                    # Excess sediment deposits
                    deposit = min(s - dep, dep * 0.5)
                    terrain[r][c] += deposit
                    s -= deposit
                new_water[r][c] = max(0.0, w)
                new_sediment[r][c] = max(0.0, s)

        self.erosion_water = new_water
        self.erosion_sediment = new_sediment
        self.erosion_total_eroded += total_eroded
        self.erosion_generation += 1

        # Water exits at boundaries (drain off edges)
        for r in range(rows):
            for c in (0, cols - 1):
                self.erosion_water[r][c] *= 0.5
                self.erosion_sediment[r][c] *= 0.5
        for c in range(cols):
            for r in (0, rows - 1):
                self.erosion_water[r][c] *= 0.5
                self.erosion_sediment[r][c] *= 0.5

    def _handle_erosion_menu_key(self, key: int) -> bool:
        """Handle input in erosion preset menu."""
        n = len(self.EROSION_PRESETS)
        if key in (ord("j"), curses.KEY_DOWN):
            self.erosion_menu_sel = (self.erosion_menu_sel + 1) % n
        elif key in (ord("k"), curses.KEY_UP):
            self.erosion_menu_sel = (self.erosion_menu_sel - 1) % n
        elif key in (ord("\n"), ord("\r")):
            self._erosion_init(self.erosion_menu_sel)
        elif key in (ord("q"), 27):
            self.erosion_menu = False
            self._flash("Erosion cancelled")
        return True

    def _handle_erosion_key(self, key: int) -> bool:
        """Handle input in active erosion simulation."""
        if key == ord(" "):
            self.erosion_running = not self.erosion_running
        elif key in (ord("n"), ord(".")):
            for _ in range(self.erosion_steps_per_frame):
                self._erosion_step()
        elif key == ord("r"):
            idx = next((i for i, p in enumerate(self.EROSION_PRESETS)
                        if p[0] == self.erosion_preset_name), 0)
            self._erosion_init(idx)
            self.erosion_running = False
        elif key in (ord("R"), ord("m")):
            self.erosion_mode = False
            self.erosion_running = False
            self.erosion_menu = True
            self.erosion_menu_sel = 0
        elif key == ord("w") or key == ord("W"):
            delta = 0.002 if key == ord("w") else -0.002
            self.erosion_rain_rate = max(0.001, min(0.05, self.erosion_rain_rate + delta))
            self._flash(f"Rain rate = {self.erosion_rain_rate:.3f}")
        elif key == ord("e") or key == ord("E"):
            delta = 0.002 if key == ord("e") else -0.002
            self.erosion_solubility = max(0.001, min(0.05, self.erosion_solubility + delta))
            self._flash(f"Solubility = {self.erosion_solubility:.3f}")
        elif key == ord("+") or key == ord("="):
            self.erosion_steps_per_frame = min(20, self.erosion_steps_per_frame + 1)
            self._flash(f"Steps/frame: {self.erosion_steps_per_frame}")
        elif key == ord("-"):
            self.erosion_steps_per_frame = max(1, self.erosion_steps_per_frame - 1)
            self._flash(f"Steps/frame: {self.erosion_steps_per_frame}")
        elif key == ord("<") or key == ord(","):
            self.speed_idx = max(0, self.speed_idx - 1)
        elif key == ord(">"):
            self.speed_idx = min(len(SPEEDS) - 1, self.speed_idx + 1)
        elif key in (ord("q"), 27):
            self._exit_erosion_mode()
        else:
            return True
        return True

    def _draw_erosion_menu(self, max_y: int, max_x: int):
        """Draw the erosion preset selection menu."""
        self.stdscr.erase()
        title = "── Hydraulic Erosion ── Select Scenario ──"
        try:
            self.stdscr.addstr(1, max(0, (max_x - len(title)) // 2), title,
                               curses.color_pair(7) | curses.A_BOLD)
        except curses.error:
            pass

        for i, (name, desc, *_rest) in enumerate(self.EROSION_PRESETS):
            y = 3 + i * 2
            if y >= max_y - 2:
                break
            line = f"  {name:<24s}  {desc}"
            attr = curses.color_pair(6)
            if i == self.erosion_menu_sel:
                attr = curses.color_pair(3) | curses.A_REVERSE
            try:
                self.stdscr.addstr(y, 2, line[:max_x - 4], attr)
            except curses.error:
                pass

        hint = " [j/k]=navigate  [Enter]=select  [q]=cancel"
        try:
            self.stdscr.addstr(max_y - 1, 0, hint[:max_x - 1], curses.color_pair(6) | curses.A_DIM)
        except curses.error:
            pass

    def _draw_erosion(self, max_y: int, max_x: int):
        """Draw the active Hydraulic Erosion simulation."""
        self.stdscr.erase()
        terrain = self.erosion_terrain
        water = self.erosion_water
        rows, cols = self.erosion_rows, self.erosion_cols
        gen = self.erosion_generation
        state = "▶ RUNNING" if self.erosion_running else "⏸ PAUSED"

        # Title bar
        title = (f" Erosion: {self.erosion_preset_name}  |  step {gen}"
                 f"  |  eroded: {self.erosion_total_eroded:.2f}"
                 f"  |  rain={self.erosion_rain_rate:.3f}"
                 f"  |  {state}")
        try:
            self.stdscr.addstr(0, 0, title[:max_x - 1], curses.color_pair(7) | curses.A_BOLD)
        except curses.error:
            pass

        view_rows = max_y - 3
        view_cols = (max_x - 1) // 2

        # Terrain height-based color gradient + water overlay
        # Color pairs: 90=deep, 91-96=terrain gradient, 97=peak, 98=shallow water, 99=deep water
        for r in range(min(rows, view_rows)):
            for c in range(min(cols, view_cols)):
                sx = c * 2
                sy = 1 + r
                h = terrain[r][c]
                w = water[r][c]

                if w > 0.02:
                    # Water cell — blue tones based on depth
                    if w > 0.08:
                        attr = curses.color_pair(99) | curses.A_BOLD
                        ch = "██"
                    elif w > 0.04:
                        attr = curses.color_pair(98) | curses.A_BOLD
                        ch = "▓▓"
                    else:
                        attr = curses.color_pair(98)
                        ch = "░░"
                else:
                    # Terrain cell — color by height
                    if h < 0.12:
                        attr = curses.color_pair(90)
                        ch = "░░"
                    elif h < 0.25:
                        attr = curses.color_pair(91)
                        ch = "░░"
                    elif h < 0.38:
                        attr = curses.color_pair(92)
                        ch = "▒▒"
                    elif h < 0.50:
                        attr = curses.color_pair(93)
                        ch = "▒▒"
                    elif h < 0.62:
                        attr = curses.color_pair(94)
                        ch = "▓▓"
                    elif h < 0.75:
                        attr = curses.color_pair(95)
                        ch = "▓▓"
                    elif h < 0.88:
                        attr = curses.color_pair(96) | curses.A_BOLD
                        ch = "██"
                    else:
                        attr = curses.color_pair(97) | curses.A_BOLD
                        ch = "██"
                try:
                    self.stdscr.addstr(sy, sx, ch, attr)
                except curses.error:
                    pass

        # Hint bar
        hint_y = max_y - 1
        if hint_y > 0:
            now = time.monotonic()
            if self.message and now - self.message_time < 3.0:
                hint = f" {self.message}"
            else:
                hint = " [Space]=play [n]=step [w/W]=rain+/- [e/E]=erosion+/- [+/-]=steps/f [r]=reset [R]=menu [q]=exit"
            hint = hint[:max_x - 1]
            try:
                self.stdscr.addstr(hint_y, 0, hint, curses.color_pair(6) | curses.A_DIM)
            except curses.error:
                pass


    # ── Voronoi Crystal Growth ───────────────────────────────────────────────

    VORONOI_PRESETS = [
        ("Fine Microstructure",
         "Many small grains — dense polycrystalline texture",
         60, 0.20, "random"),
        ("Coarse Grains",
         "Few large crystals — visible anisotropic facets",
         12, 0.45, "random"),
        ("Columnar Growth",
         "Seeds along one edge — columnar crystal columns",
         25, 0.50, "edge"),
        ("Dendritic Arms",
         "High anisotropy — branching faceted domains",
         20, 0.70, "random"),
        ("Isotropic Foam",
         "No preferred direction — soap-bubble-like cells",
         35, 0.0, "random"),
        ("Sparse Nucleation",
         "Very few seeds — large irregular territories",
         6, 0.35, "random"),
        ("Bicrystal",
         "Two grains meeting — single grain boundary study",
         2, 0.40, "bicrystal"),
        ("Radial Burst",
         "Seeds from centre — radial competitive growth",
         20, 0.30, "center"),
    ]

    def _enter_voronoi_mode(self):
        """Enter Voronoi Crystal Growth mode — show preset menu."""
        self.voronoi_menu = True
        self.voronoi_menu_sel = 0
        self._flash("Voronoi Crystal Growth — select a scenario")

    def _exit_voronoi_mode(self):
        """Exit Voronoi Crystal Growth mode."""
        self.voronoi_mode = False
        self.voronoi_menu = False
        self.voronoi_running = False
        self.voronoi_grid = []
        self.voronoi_seeds = []
        self.voronoi_angles = []
        self.voronoi_frontier = []
        self._flash("Voronoi Crystal Growth OFF")

    def _voronoi_init(self, preset_idx: int):
        """Initialize voronoi simulation with selected preset."""
        name, _desc, num_seeds, aniso, seed_mode = self.VORONOI_PRESETS[preset_idx]
        max_y, max_x = self.stdscr.getmaxyx()
        rows = max_y - 2
        cols = (max_x - 1) // 2
        if rows < 5 or cols < 5:
            return

        self.voronoi_rows = rows
        self.voronoi_cols = cols
        self.voronoi_num_seeds = num_seeds
        self.voronoi_aniso = aniso
        self.voronoi_preset_name = name
        self.voronoi_generation = 0
        self.voronoi_grid = [[-1] * cols for _ in range(rows)]
        self.voronoi_seeds = []
        self.voronoi_angles = []
        self.voronoi_frontier = []

        # Place seeds based on mode
        if seed_mode == "edge":
            # Seeds along left edge
            for i in range(num_seeds):
                r = int((i + 0.5) * rows / num_seeds)
                c = 0
                self.voronoi_seeds.append((r, c))
                self.voronoi_angles.append(random.random() * math.pi * 2)
        elif seed_mode == "bicrystal":
            # Two seeds on opposite sides
            self.voronoi_seeds.append((rows // 2, cols // 4))
            self.voronoi_angles.append(0.0)
            self.voronoi_seeds.append((rows // 2, 3 * cols // 4))
            self.voronoi_angles.append(math.pi / 3)
        elif seed_mode == "center":
            # Seeds clustered near center
            cr, cc = rows // 2, cols // 2
            for _i in range(num_seeds):
                angle = random.random() * math.pi * 2
                dist = random.random() * min(rows, cols) * 0.15
                r = int(cr + dist * math.sin(angle))
                c = int(cc + dist * math.cos(angle))
                r = max(0, min(rows - 1, r))
                c = max(0, min(cols - 1, c))
                self.voronoi_seeds.append((r, c))
                self.voronoi_angles.append(random.random() * math.pi * 2)
        else:
            # Random placement
            for _i in range(num_seeds):
                r = random.randint(0, rows - 1)
                c = random.randint(0, cols - 1)
                self.voronoi_seeds.append((r, c))
                self.voronoi_angles.append(random.random() * math.pi * 2)

        # Initialize seeds on grid and frontier
        for gid, (r, c) in enumerate(self.voronoi_seeds):
            self.voronoi_grid[r][c] = gid
            # Add neighbors to frontier
            for dr in (-1, 0, 1):
                for dc in (-1, 0, 1):
                    if dr == 0 and dc == 0:
                        continue
                    nr, nc = r + dr, c + dc
                    if 0 <= nr < rows and 0 <= nc < cols and self.voronoi_grid[nr][nc] == -1:
                        self.voronoi_frontier.append((nr, nc, gid))

        self.voronoi_grain_count = len(self.voronoi_seeds)
        self.voronoi_menu = False
        self.voronoi_mode = True
        self.voronoi_running = True

    def _voronoi_step(self):
        """Advance voronoi crystal growth by one step."""
        if not self.voronoi_frontier:
            return

        rows = self.voronoi_rows
        cols = self.voronoi_cols
        grid = self.voronoi_grid
        aniso = self.voronoi_aniso

        # Process frontier in random order for natural growth
        random.shuffle(self.voronoi_frontier)

        new_frontier: list[tuple[int, int, int]] = []
        claimed_this_step: set[tuple[int, int]] = set()

        for r, c, gid in self.voronoi_frontier:
            if grid[r][c] != -1:
                continue  # already claimed

            # Anisotropic growth probability
            # Direction from seed to this cell
            sr, sc = self.voronoi_seeds[gid]
            dr = r - sr
            dc = c - sc
            if dr == 0 and dc == 0:
                prob = 1.0
            else:
                angle_to_cell = math.atan2(dr, dc)
                preferred = self.voronoi_angles[gid]
                # Angular difference — growth is faster along preferred direction
                diff = abs(angle_to_cell - preferred)
                if diff > math.pi:
                    diff = 2 * math.pi - diff
                # Probability: 1.0 along preferred axis, reduced perpendicular
                prob = 1.0 - aniso * (diff / math.pi)
                prob = max(0.1, prob)

            if random.random() < prob:
                grid[r][c] = gid
                claimed_this_step.add((r, c))
                # Add unclaimed neighbors to frontier
                for ddr in (-1, 0, 1):
                    for ddc in (-1, 0, 1):
                        if ddr == 0 and ddc == 0:
                            continue
                        nr, nc = r + ddr, c + ddc
                        if 0 <= nr < rows and 0 <= nc < cols and grid[nr][nc] == -1:
                            if (nr, nc) not in claimed_this_step:
                                new_frontier.append((nr, nc, gid))
            else:
                # Keep in frontier for next step
                new_frontier.append((r, c, gid))

        self.voronoi_frontier = new_frontier
        self.voronoi_generation += 1

    def _voronoi_is_boundary(self, r: int, c: int) -> bool:
        """Check if cell (r, c) is on a grain boundary."""
        grid = self.voronoi_grid
        gid = grid[r][c]
        if gid == -1:
            return False
        rows = self.voronoi_rows
        cols = self.voronoi_cols
        for dr in (-1, 0, 1):
            for dc in (-1, 0, 1):
                if dr == 0 and dc == 0:
                    continue
                nr, nc = r + dr, c + dc
                if 0 <= nr < rows and 0 <= nc < cols:
                    ngid = grid[nr][nc]
                    if ngid != -1 and ngid != gid:
                        return True
        return False

    def _handle_voronoi_menu_key(self, key: int) -> bool:
        """Handle keys in voronoi preset menu."""
        if key == curses.KEY_UP:
            self.voronoi_menu_sel = (self.voronoi_menu_sel - 1) % len(self.VORONOI_PRESETS)
        elif key == curses.KEY_DOWN:
            self.voronoi_menu_sel = (self.voronoi_menu_sel + 1) % len(self.VORONOI_PRESETS)
        elif key in (curses.KEY_ENTER, 10, 13):
            self._voronoi_init(self.voronoi_menu_sel)
        elif key == 27 or key == ord("q") or key == ord("%"):
            self.voronoi_menu = False
            self._flash("Voronoi Crystal Growth cancelled")
        else:
            return True
        return True

    def _handle_voronoi_key(self, key: int) -> bool:
        """Handle keys during voronoi simulation."""
        if key == ord(" "):
            self.voronoi_running = not self.voronoi_running
        elif key == ord("n"):
            self._voronoi_step()
        elif key == ord("+") or key == ord("="):
            self.voronoi_steps_per_frame = min(50, self.voronoi_steps_per_frame + 2)
            self._flash(f"Steps/frame: {self.voronoi_steps_per_frame}")
        elif key == ord("-"):
            self.voronoi_steps_per_frame = max(1, self.voronoi_steps_per_frame - 2)
            self._flash(f"Steps/frame: {self.voronoi_steps_per_frame}")
        elif key == ord("r"):
            # Reset with same preset
            idx = self.voronoi_menu_sel
            self._voronoi_init(idx)
        elif key == ord("R"):
            self.voronoi_mode = False
            self.voronoi_menu = True
            self.voronoi_running = False
        elif key == ord("q") or key == ord("%"):
            self._exit_voronoi_mode()
        elif key == ord("a"):
            # Increase anisotropy
            self.voronoi_aniso = min(0.9, self.voronoi_aniso + 0.05)
            self._flash(f"Anisotropy: {self.voronoi_aniso:.2f}")
        elif key == ord("A"):
            # Decrease anisotropy
            self.voronoi_aniso = max(0.0, self.voronoi_aniso - 0.05)
            self._flash(f"Anisotropy: {self.voronoi_aniso:.2f}")
        else:
            return True
        return True

    def _draw_voronoi_menu(self, max_y: int, max_x: int):
        """Draw the voronoi preset selection menu."""
        self.stdscr.erase()
        title = "── Voronoi Crystal Growth ── Select Scenario ──"
        try:
            self.stdscr.addstr(1, max(0, (max_x - len(title)) // 2), title,
                               curses.color_pair(7) | curses.A_BOLD)
        except curses.error:
            pass

        for i, (name, desc, *_rest) in enumerate(self.VORONOI_PRESETS):
            y = 3 + i * 2
            if y >= max_y - 2:
                break
            marker = "▸ " if i == self.voronoi_menu_sel else "  "
            attr = curses.A_BOLD if i == self.voronoi_menu_sel else 0
            line = f"{marker}{name}"
            try:
                self.stdscr.addstr(y, 2, line[:max_x - 3], curses.color_pair(7) | attr)
            except curses.error:
                pass
            if y + 1 < max_y - 1:
                try:
                    self.stdscr.addstr(y + 1, 6, desc[:max_x - 7], curses.color_pair(6) | curses.A_DIM)
                except curses.error:
                    pass

        # Footer
        foot_y = max_y - 1
        if foot_y > 0:
            foot = " [↑/↓]=select  [Enter]=start  [q]=cancel"
            try:
                self.stdscr.addstr(foot_y, 0, foot[:max_x - 1], curses.color_pair(6) | curses.A_DIM)
            except curses.error:
                pass

    def _draw_voronoi(self, max_y: int, max_x: int):
        """Draw the active voronoi crystal growth simulation."""
        self.stdscr.erase()
        rows = self.voronoi_rows
        cols = self.voronoi_cols
        grid = self.voronoi_grid
        gen = self.voronoi_generation
        frontier_count = len(self.voronoi_frontier)

        # Title bar
        status = "GROWING" if self.voronoi_running and frontier_count > 0 else ("COMPLETE" if frontier_count == 0 else "PAUSED")
        title = (f" Voronoi: {self.voronoi_preset_name}  |  step {gen}"
                 f"  |  grains: {self.voronoi_grain_count}"
                 f"  |  aniso: {self.voronoi_aniso:.2f}"
                 f"  |  {status}")
        try:
            self.stdscr.addstr(0, 0, title[:max_x - 1], curses.color_pair(7) | curses.A_BOLD)
        except curses.error:
            pass

        view_rows = min(rows, max_y - 2)
        view_cols = min(cols, (max_x - 1) // 2)

        num_grain_colors = 15  # pairs 100-114
        for r in range(view_rows):
            for c in range(view_cols):
                sy = r + 1
                sx = c * 2
                gid = grid[r][c]
                if gid == -1:
                    # Unclaimed — empty space
                    ch = "  "
                    attr = 0
                elif self._voronoi_is_boundary(r, c):
                    # Grain boundary
                    ch = "▒▒"
                    attr = curses.color_pair(115) | curses.A_DIM
                else:
                    # Interior of grain — color based on grain ID
                    color_idx = 100 + (gid % num_grain_colors)
                    ch = "██"
                    attr = curses.color_pair(color_idx)
                try:
                    self.stdscr.addstr(sy, sx, ch, attr)
                except curses.error:
                    pass

        # Hint bar
        hint_y = max_y - 1
        if hint_y > 0:
            now = time.monotonic()
            if self.message and now - self.message_time < 3.0:
                hint = f" {self.message}"
            else:
                hint = " [Space]=play [n]=step [a/A]=aniso+/- [+/-]=steps/f [r]=reset [R]=menu [q]=exit"
            hint = hint[:max_x - 1]
            try:
                self.stdscr.addstr(hint_y, 0, hint, curses.color_pair(6) | curses.A_DIM)
            except curses.error:
                pass


